    # app.run(debug=True, host='0.0.0.0', port=5000)
    #
    # To simulate high traffic, ensure your Elasticsearch instance is robust
    # and consider using a load balancer in front of multiple Flask instances.
    app.run(host='0.0.0.0', port=5000)